namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public static class RecipeData
{
    public static List<string> Categories => new()
    {
        "Breakfast",
        "Lunch",
        "Dinner",
        "Desserts",
        "Snacks",
        "Beverages"
    };

    public static List<Recipe> Recipes => new()
    {
        new Recipe
        {
            Id = 1, Title = "Classic Pancakes", Category = "Breakfast",
            Ingredients = "2 cups flour\n2 eggs\n1.5 cups milk\n2 tbsp sugar\n1 tsp baking powder\nPinch of salt",
            Steps = "1. Mix dry ingredients.\n2. Whisk eggs and milk together.\n3. Combine wet and dry ingredients.\n4. Cook on a greased griddle until bubbles form, then flip.",
            AverageRating = 4.5, RatingCount = 12
        },
        new Recipe
        {
            Id = 2, Title = "Avocado Toast", Category = "Breakfast",
            Ingredients = "2 slices sourdough bread\n1 ripe avocado\nSalt and pepper\nRed pepper flakes\nLemon juice",
            Steps = "1. Toast bread until golden.\n2. Mash avocado with lemon juice, salt, and pepper.\n3. Spread on toast.\n4. Sprinkle with red pepper flakes.",
            AverageRating = 4.2, RatingCount = 8
        },
        new Recipe
        {
            Id = 3, Title = "Grilled Chicken Salad", Category = "Lunch",
            Ingredients = "2 chicken breasts\nMixed greens\nCherry tomatoes\nCucumber\nOlive oil\nLemon dressing",
            Steps = "1. Season and grill chicken breasts.\n2. Slice chicken.\n3. Toss greens with tomatoes and cucumber.\n4. Top with chicken and drizzle dressing.",
            AverageRating = 4.7, RatingCount = 15
        },
        new Recipe
        {
            Id = 4, Title = "Tomato Soup", Category = "Lunch",
            Ingredients = "6 large tomatoes\n1 onion\n3 cloves garlic\nVegetable broth\nBasil\nCream",
            Steps = "1. Roast tomatoes, onion, and garlic.\n2. Blend with broth until smooth.\n3. Simmer for 15 minutes.\n4. Stir in cream and fresh basil.",
            AverageRating = 4.3, RatingCount = 10
        },
        new Recipe
        {
            Id = 5, Title = "Spaghetti Bolognese", Category = "Dinner",
            Ingredients = "400g spaghetti\n500g ground beef\n1 can crushed tomatoes\n1 onion\n2 cloves garlic\nItalian herbs",
            Steps = "1. Cook spaghetti al dente.\n2. Brown beef with onion and garlic.\n3. Add tomatoes and herbs, simmer 20 min.\n4. Serve sauce over pasta.",
            AverageRating = 4.8, RatingCount = 22
        },
        new Recipe
        {
            Id = 6, Title = "Baked Salmon", Category = "Dinner",
            Ingredients = "4 salmon fillets\nLemon\nDill\nGarlic butter\nSalt and pepper\nAsparagus",
            Steps = "1. Preheat oven to 200°C.\n2. Place salmon on baking sheet.\n3. Top with garlic butter, lemon, and dill.\n4. Bake 12-15 minutes.",
            AverageRating = 4.6, RatingCount = 18
        },
        new Recipe
        {
            Id = 7, Title = "Chocolate Lava Cake", Category = "Desserts",
            Ingredients = "200g dark chocolate\n100g butter\n2 eggs\n2 egg yolks\n50g sugar\n30g flour",
            Steps = "1. Melt chocolate and butter together.\n2. Whisk eggs, yolks, and sugar.\n3. Fold in chocolate mixture and flour.\n4. Bake at 220°C for 10-12 minutes.",
            AverageRating = 4.9, RatingCount = 30
        },
        new Recipe
        {
            Id = 8, Title = "Trail Mix Energy Bites", Category = "Snacks",
            Ingredients = "1 cup oats\n1/2 cup peanut butter\n1/3 cup honey\n1/2 cup chocolate chips\n1/4 cup flaxseed",
            Steps = "1. Mix all ingredients in a bowl.\n2. Refrigerate for 30 minutes.\n3. Roll into small balls.\n4. Store in refrigerator.",
            AverageRating = 4.4, RatingCount = 9
        },
        new Recipe
        {
            Id = 9, Title = "Mango Smoothie", Category = "Beverages",
            Ingredients = "1 mango\n1 banana\n1 cup yogurt\n1/2 cup orange juice\nIce cubes",
            Steps = "1. Peel and chop mango and banana.\n2. Add all ingredients to blender.\n3. Blend until smooth.\n4. Serve immediately.",
            AverageRating = 4.1, RatingCount = 7
        }
    };
}

