@page "/recipes/{Category}"
@using RecipeCommunity.Models

<PageTitle>@Category Recipes</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@Category</li>
        </ol>
    </nav>

    <h1>@Category Recipes</h1>

    @if (recipes.Any())
    {
        <div class="row">
            @foreach (var recipe in recipes)
            {
                <div class="col-md-6 mb-3">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text">
                                <span class="text-warning">@GetStars(recipe.AverageRating)</span>
                                <small class="text-muted">(@recipe.RatingCount ratings)</small>
                            </p>
                            <a href="/recipe/@recipe.Id" class="btn btn-outline-primary btn-sm">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
    else
    {
        <p class="text-muted">No recipes found in this category.</p>
    }
</div>

@code {
    [Parameter]
    public string Category { get; set; } = string.Empty;

    private List<Recipe> recipes = new();

    protected override void OnParametersSet()
    {
        recipes = RecipeData.Recipes
            .Where(r => r.Category.Equals(Category, StringComparison.OrdinalIgnoreCase))
            .ToList();

        // Title-case the category for display
        if (recipes.Any())
            Category = recipes.First().Category;
    }

    private string GetStars(double rating)
    {
        int full = (int)rating;
        bool half = rating - full >= 0.5;
        var stars = new string('★', full);
        if (half) stars += "½";
        stars += new string('☆', 5 - full - (half ? 1 : 0));
        return stars;
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Models

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            @if (recipe != null)
            {
                <li class="breadcrumb-item"><a href="/recipes/@recipe.Category.ToLower()">@recipe.Category</a></li>
                <li class="breadcrumb-item active">@recipe.Title</li>
            }
        </ol>
    </nav>

    @if (recipe != null)
    {
        <h1>@recipe.Title</h1>
        <span class="badge bg-secondary mb-3">@recipe.Category</span>

        <div class="row mt-3">
            <div class="col-md-4">
                <div class="card">
                    <div class="card-header"><strong>Ingredients</strong></div>
                    <div class="card-body">
                        <ul class="list-unstyled mb-0">
                            @foreach (var ingredient in recipe.Ingredients.Split('\n'))
                            {
                                <li>• @ingredient</li>
                            }
                        </ul>
                    </div>
                </div>
            </div>
            <div class="col-md-8">
                <div class="card">
                    <div class="card-header"><strong>Steps</strong></div>
                    <div class="card-body">
                        @foreach (var step in recipe.Steps.Split('\n'))
                        {
                            <p class="mb-2">@step</p>
                        }
                    </div>
                </div>
            </div>
        </div>

        <div class="card mt-4">
            <div class="card-body">
                <h5>Rate this Recipe</h5>
                <RecipeCommunity.Client.Pages.StarRating @rendermode="InteractiveWebAssembly"
                    RecipeId="recipe.Id"
                    CurrentRating="recipe.AverageRating"
                    RatingCount="recipe.RatingCount" />
            </div>
        </div>
    }
    else
    {
        <div class="alert alert-warning">Recipe not found.</div>
    }
</div>

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeData.Recipes.FirstOrDefault(r => r.Id == Id);
    }
}

@page "/submit"
@rendermode InteractiveWebAssembly

<PageTitle>Submit a Recipe</PageTitle>

<div class="container">
    <h1>Submit a Recipe</h1>
    <p class="text-muted">Share your favorite recipe with the community.</p>

    @if (submitted)
    {
        <div class="alert alert-success">
            <h4>Thank you!</h4>
            <p>Your recipe "<strong>@model.Title</strong>" has been submitted successfully.</p>
            <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
        </div>
    }
    else
    {
        <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" />

            <div class="mb-3">
                <label for="title" class="form-label">Recipe Title</label>
                <InputText id="title" class="form-control" @bind-Value="model.Title" placeholder="e.g., Grandma's Apple Pie" />
                <ValidationMessage For="() => model.Title" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="category" class="form-label">Category</label>
                <InputSelect id="category" class="form-select" @bind-Value="model.Category">
                    <option value="">-- Select a category --</option>
                    <option value="Breakfast">Breakfast</option>
                    <option value="Lunch">Lunch</option>
                    <option value="Dinner">Dinner</option>
                    <option value="Desserts">Desserts</option>
                    <option value="Snacks">Snacks</option>
                    <option value="Beverages">Beverages</option>
                </InputSelect>
                <ValidationMessage For="() => model.Category" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="ingredients" class="form-label">Ingredients</label>
                <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="model.Ingredients"
                    placeholder="One ingredient per line" />
                <ValidationMessage For="() => model.Ingredients" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="steps" class="form-label">Steps</label>
                <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="model.Steps"
                    placeholder="Describe each step" />
                <ValidationMessage For="() => model.Steps" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-success">Submit Recipe</button>
        </EditForm>
    }
</div>

@code {
    private RecipeFormModel model = new();
    private bool submitted = false;

    private void HandleSubmit()
    {
        submitted = true;
    }

    private void Reset()
    {
        model = new();
        submitted = false;
    }

    public class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, ErrorMessage = "Title must be under 100 characters.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required.")]
        public string Steps { get; set; } = string.Empty;
    }
}

@namespace RecipeCommunity.Client.Pages

<div class="d-flex align-items-center gap-2">
    <div class="star-rating" style="font-size: 1.5rem; cursor: pointer;">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="@(star <= displayRating ? "text-warning" : "text-muted")"
                  @onclick="() => Rate(star)"
                  @onmouseover="() => displayRating = star"
                  @onmouseout="() => displayRating = userRating ?? (int)Math.Round(CurrentRating)">
                ★
            </span>
        }
    </div>
    <span class="text-muted small">
        @if (userRating.HasValue)
        {
            <text>You rated @userRating stars!</text>
        }
        else
        {
            <text>@CurrentRating.ToString("0.0") avg (@RatingCount ratings)</text>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int? userRating;
    private int displayRating;

    protected override void OnParametersSet()
    {
        displayRating = (int)Math.Round(CurrentRating);
    }

    private void Rate(int stars)
    {
        userRating = stars;
        displayRating = stars;
    }
}

